var mock = new Mock<IEnvironmentProvider>();
mock.Setup(e => e.MachineName).Returns("TEST-HOST");
mock.Setup(e => e.GetEnvironmentVariable("APP_ENV")).Returns("staging");
var svc = new MyService(mock.Object);
